import itertools
class Solution:
    def minOperations(self, nums, k):
        n = len(nums)
        if k == 0:
            return 0
        if k > n // 2:
            return -1
        best = None
        for combo in itertools.combinations(range(n), k):
            s = set(combo)
            ok = True
            for i in combo:
                if (i + 1) % n in s or (i - 1) % n in s:
                    ok = False
                    break
            if not ok:
                continue
            cost = 0
            for i in combo:
                l = nums[(i - 1) % n]
                r = nums[(i + 1) % n]
                need = max(l, r) + 1
                cost += max(0, need - nums[i])
            if best is None or cost < best:
                best = cost
        return best if best is not None else -1

