class Solution:
    def minOperations(self, nums, k: int) -> int:
        n = len(nums)
        if k == 0:
            return 0
        if k > n // 2:
            return -1
        costs = [0] * n
        for i in range(n):
            l = nums[(i - 1) % n]
            r = nums[(i + 1) % n]
            need = max(l, r) + 1
            costs[i] = max(0, need - nums[i])

        INF = float('inf')

        def linear_min_cost(arr, j):
            m = len(arr)
            if j == 0:
                return 0
            if j > (m + 1) // 2:
                return INF
            prev2 = [INF] * (j + 1)
            prev1 = [INF] * (j + 1)
            prev2[0] = 0
            prev1[0] = 0
            if m >= 1:
                prev1[1] = arr[0]
            for i in range(1, m):
                cur = [INF] * (j + 1)
                cur[0] = 0
                for t in range(1, j + 1):
                    best = prev1[t]
                    if prev2[t - 1] != INF:
                        cand = prev2[t - 1] + arr[i]
                        if cand < best:
                            best = cand
                    cur[t] = best
                prev2 = prev1
                prev1 = cur
            return prev1[j]

        a = linear_min_cost(costs[1:], k)
        if n >= 3:
            b_inner = linear_min_cost(costs[2:n - 1], k - 1)
        else:
            b_inner = 0 if k - 1 == 0 else INF
        b = costs[0] + b_inner if b_inner != INF else INF
        ans = min(a, b)
        return ans if ans != INF else -1

