var minOperations = function(nums, k) {
    const n = nums.length;
    if (k === 0) return 0;
    if (k > Math.floor(n / 2)) return -1;
    const costs = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        const l = nums[(i - 1 + n) % n];
        const r = nums[(i + 1) % n];
        const need = Math.max(l, r) + 1;
        costs[i] = Math.max(0, need - nums[i]);
    }
    const INF = Infinity;

    function linearMinCost(arr, j) {
        const m = arr.length;
        if (j === 0) return 0;
        if (j > Math.floor((m + 1) / 2)) return INF;
        let prev2 = new Array(j + 1).fill(INF);
        let prev1 = new Array(j + 1).fill(INF);
        prev2[0] = 0;
        prev1[0] = 0;
        if (m >= 1) prev1[1] = arr[0];
        for (let i = 1; i < m; i++) {
            const cur = new Array(j + 1).fill(INF);
            cur[0] = 0;
            for (let t = 1; t <= j; t++) {
                let best = prev1[t];
                if (prev2[t - 1] !== INF) {
                    const cand = prev2[t - 1] + arr[i];
                    if (cand < best) best = cand;
                }
                cur[t] = best;
            }
            prev2 = prev1;
            prev1 = cur;
        }
        return prev1[j];
    }

    const a = linearMinCost(costs.slice(1), k);
    let bInner;
    if (n >= 3) {
        bInner = linearMinCost(costs.slice(2, n - 1), k - 1);
    } else {
        bInner = (k - 1 === 0) ? 0 : INF;
    }
    const b = (bInner !== INF) ? costs[0] + bInner : INF;
    const ans = Math.min(a, b);
    return ans !== INF ? ans : -1;
};
